// ───────────────────────────────────────────────────────────────────────
// Regexes — one per token. Each is anchored with `<<NAME:` prefix and
// terminates at `>>`. Payload body rejects `>` and CRLF so a stray `>`
// inside the payload terminates cleanly instead of eating downstream
// tokens.
// ───────────────────────────────────────────────────────────────────────
export const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
export const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
export const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
// 2026-05-02: reason bodies additionally reject `<` so an agent quoting
// other tokens inside a reason (e.g. <<GOAL_DONE:describes <<RESTART:foo>>>>)
// can't collapse the outer match onto the inner `>>`. SEND_FILE / SCHEDULE
// / ASK bodies keep `<` allowed because their payloads (paths / time specs
// / key=val) don't typically contain it, and banning `<` there would break
// legitimate payloads like URLs.
export const SKILL_USED_RE =
  /<<SKILL_USED:\s*([a-zA-Z0-9_-]{1,60})\s*\|\s*([^<>|\r\n]{0,500})\s*>>/g;
export const GOAL_DONE_RE = /<<GOAL_DONE:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
// RESTART token (C3, 2026-05-02). `<<RESTART:reason>>` or bare
// `<<RESTART>>` asks the bridge to exit(1) so the supervisor respawns us.
// The actual guardrail (goal active? cooldown? cap?) lives in runPrompt;
// this regex only extracts the payload. Reason is 1-500 chars, rejects
// `<` / `>` / `|` / CRLF so malformed payloads (including agents quoting
// other tokens inside the reason) fall through as visible text instead
// of collapsing the match on a nested `>>`.
export const RESTART_RE = /<<RESTART:\s*([^<>|\r\n]{1,500}?)\s*>>/g;
export const RESTART_BARE_RE = /<<RESTART>>/g;
export const RESTART_BARE_REASON = "agent-requested-restart";
export const STICKER_RE = /<<STICKER:\s*([a-z_]{1,20})\s*>>/g;
export const CONTINUE_RE = /<<CONTINUE>>/g;

// ASK sub-regexes (kept here because ASK payload parsing lives here too).
