export const SCHEDULE_MAX_PER_MSG = 3;
export const SKILL_USED_MAX_PER_MSG = 5;
export const GOAL_DONE_MAX_PER_MSG = 1;
// RESTART: only honour the first <<RESTART:...>> in one reply. Extra
